import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append('\n');
        }
        // Replace escaped "\n" sequences with actual newlines
        String input = raw.toString().replace("\\n", "\n");
        StringTokenizer st = new StringTokenizer(input);
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            long[] a = new long[N];
            long[] b = new long[M];
            for (int i = 0; i < N; i++) a[i] = Long.parseLong(st.nextToken());
            for (int i = 0; i < M; i++) b[i] = Long.parseLong(st.nextToken());
            int i = 0, j = 0;
            long last = Long.MIN_VALUE;
            StringBuilder lineOut = new StringBuilder();
            while (i < N && j < M) {
                long val;
                if (a[i] < b[j]) {
                    val = a[i++];
                } else if (a[i] > b[j]) {
                    val = b[j++];
                } else {
                    val = a[i];
                    i++; j++;
                }
                if (val != last) {
                    lineOut.append(val).append(' ');
                    last = val;
                }
            }
            while (i < N) {
                long val = a[i++];
                if (val != last) {
                    lineOut.append(val).append(' ');
                    last = val;
                }
            }
            while (j < M) {
                long val = b[j++];
                if (val != last) {
                    lineOut.append(val).append(' ');
                    last = val;
                }
            }
            out.append(lineOut.toString().trim());
            if (t != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

